def decrypt_credit_card(encrypted_number):
    # Initialize the AES cipher with the encryption key from the app config
    cipher = AES.new(app.config['ENCRYPTION_KEY'], AES.MODE_ECB)
    
    # Decrypt the encrypted credit card number using AES-256 in ECB mode
